import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const MONTH_NAMES = ["January","February","March","April","May","June","July","August","September","October","November","December"];

const FAQS = [
  { q: "What is a fertile window?", a: "The fertile window is the 5-6 days each cycle when pregnancy is possible: the 5 days before ovulation and the day of ovulation itself. Sperm can survive 3-5 days in the reproductive tract, while the egg survives only 12-24 hours after ovulation. The highest conception rates occur with intercourse 1-2 days before ovulation." },
  { q: "How is ovulation date calculated from cycle length?", a: "Ovulation typically occurs 14 days before the next period, regardless of cycle length. Formula: Ovulation Day = Cycle Length - 14 (counting from the first day of LMP). For a 28-day cycle: day 14. For a 32-day cycle: day 18. For a 24-day cycle: day 10. This '14-day rule' applies to most women with regular cycles." },
  { q: "What are signs of ovulation?", a: "Physical signs of ovulation: slight rise in basal body temperature (BBT) of 0.2-0.5- that persists for 3+ days, cervical mucus becomes clear, slippery, and stretchy ('egg-white' consistency), mild one-sided lower abdominal cramping (mittelschmerz), increased libido, LH surge on ovulation predictor kits (OPK tests turn positive 12-36 hours before ovulation)." },
  { q: "Can cycle length affect conception timing?", a: "Yes - irregular cycles make timing more challenging because ovulation varies month to month. Tracking multiple cycles with a basal body temperature chart and OPK tests provides a more accurate picture. On average, only 30% of cycles have the fertile window overlap with days 10-17. Don't rely solely on calendar estimation for irregular cycles." },
  { q: "What is the best intercourse timing for conception?", a: "Research consistently shows the day before ovulation and the day of ovulation yield the highest pregnancy rates per cycle. Having intercourse every 1-2 days during the 5-day fertile window maximizes sperm availability. Daily intercourse during the fertile window does not reduce sperm quality for healthy men." },
  { q: "How long does it typically take to conceive?", a: "For couples under 35 having regular unprotected intercourse: about 85% conceive within 12 months. Monthly conception probability is approximately 20-25% for fertile couples. Age significantly affects success: average time to conception at 25 is ~3 months; at 35, ~6 months; at 40, ~12+ months. Consult a fertility specialist after 12 months of trying (or 6 months if over 35)." },
  { q: "What is an ovulation predictor kit (OPK)?", a: "OPKs detect the luteinizing hormone (LH) surge that occurs 24-36 hours before ovulation. A positive test means ovulation is imminent. Digital OPKs measure both LH and estrogen for a longer 'peak' window. OPKs are more accurate than calendar methods for timing but don't confirm ovulation occurred - only that the LH surge happened." },
  { q: "Does the fertile window change with different cycle lengths?", a: "Yes - the fertile window shifts with cycle length. For a 24-day cycle: fertile window days 5-10. For a 28-day cycle: days 9-14. For a 32-day cycle: days 13-18. For a 35-day cycle: days 16-21. The luteal phase (post-ovulation) is relatively constant at 12-16 days regardless of cycle length." },
];

const CYCLE_REFERENCE = [
  ["21-day cycle", "Day 7", "Days 2-7", "Day 21"],
  ["24-day cycle", "Day 10", "Days 5-10", "Day 24"],
  ["26-day cycle", "Day 12", "Days 7-12", "Day 26"],
  ["28-day cycle", "Day 14", "Days 9-14", "Day 28"],
  ["30-day cycle", "Day 16", "Days 11-16", "Day 30"],
  ["32-day cycle", "Day 18", "Days 13-18", "Day 32"],
  ["35-day cycle", "Day 21", "Days 16-21", "Day 35"],
];

export default function PregnancyConceptionCalculator() {
  const today = new Date();
  const [lmpStr, setLmpStr] = useState(today.toISOString().split("T")[0]);
  const [cycleLength, setCycleLength] = useState(28);

  const lmp = new Date(lmpStr);
  const valid = !isNaN(lmp.getTime());

  const ovulationDay = cycleLength - 14;
  const ovulationDate = valid ? new Date(lmp.getTime() + ovulationDay * 24 * 3600000) : null;
  const fertileStart = ovulationDate ? new Date(ovulationDate.getTime() - 5 * 24 * 3600000) : null;
  const fertileEnd = ovulationDate ? new Date(ovulationDate.getTime() + 1 * 24 * 3600000) : null;
  const nextPeriod = valid ? new Date(lmp.getTime() + cycleLength * 24 * 3600000) : null;

  const fmtDate = (d: Date) => `${MONTH_NAMES[d.getMonth()]} ${d.getDate()}, ${d.getFullYear()}`;
  const daysFromNow = (d: Date) => Math.ceil((d.getTime() - today.getTime()) / (24 * 3600000));

  return (
    <>
      <SEOHead
        title="Free Pregnancy Conception Calculator Online - Find Your Fertile Window Instantly | CalcHive"
        description="Free online conception calculator. Calculate your ovulation date and fertile window to identify the best days to conceive. 100% free, instant results, no account needed."
        canonical="/pregnancy-conception-calculator"
        keywords="free conception calculator, ovulation calculator free online, fertile window calculator free, best days to conceive calculator free, free ovulation date calculator"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Pregnancy Conception Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free conception calculator to estimate ovulation and your fertile window from cycle dates. This ovulation calculator free online also works as a fertile window calculator free, best days to conceive calculator free, and free ovulation date calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">First Day of Last Menstrual Period (LMP)</label>
              <input type="date" value={lmpStr} onChange={e => setLmpStr(e.target.value)} className="w-full sm:w-auto px-4 py-2.5 rounded-xl border border-input bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
            </div>
            <SliderInput id="cycle-cc" label="Average Cycle Length" value={cycleLength} min={21} max={45} step={1} onChange={setCycleLength} format={v => `${v} days`} testId="input-cycle" helpText={`Ovulation estimated on Day ${cycleLength - 14} of your cycle`} />
          </div>
          {valid && ovulationDate && fertileStart && fertileEnd && nextPeriod ? (
            <motion.div key={`${lmpStr}-${cycleLength}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Ovulation Date</p>
                <p className="text-3xl font-black text-white tracking-tight" data-testid="result-ovulation">{fmtDate(ovulationDate)}</p>
                <p className="text-white/70 text-sm mt-1">Day {ovulationDay} of your {cycleLength}-day cycle</p>
              </div>
              <div className="grid grid-cols-2 gap-3 mb-4">
                {[
                  { label: "Fertile Window Starts", value: fmtDate(fertileStart), sub: `${daysFromNow(fertileStart) > 0 ? "in " + daysFromNow(fertileStart) + " days" : "today or passed"}` },
                  { label: "Fertile Window Ends", value: fmtDate(fertileEnd), sub: `${daysFromNow(fertileEnd) > 0 ? "in " + daysFromNow(fertileEnd) + " days" : "today or passed"}` },
                  { label: "Best Day to Conceive", value: fmtDate(new Date(ovulationDate.getTime() - 24 * 3600000)), sub: "Day before ovulation" },
                  { label: "Next Period Expected", value: fmtDate(nextPeriod), sub: `in ${Math.max(0, daysFromNow(nextPeriod))} days` },
                ].map(({ label, value, sub }) => (
                  <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 hover:shadow-sm transition-shadow">
                    <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                    <p className="text-sm font-extrabold text-foreground">{value}</p>
                    <p className="text-xs text-muted-foreground mt-0.5">{sub}</p>
                  </div>
                ))}
              </div>
            </motion.div>
          ) : null}
        </section>
        <MedicalDisclaimer variant="pregnancy" /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Ovulation Date for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Ovulation is estimated using the "14-day rule" - ovulation occurs approximately 14 days before the next period, regardless of cycle length. The fertile window includes the 5 days before ovulation and the day of ovulation, when sperm can survive long enough to fertilize the egg.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Ovulation Day = Cycle Length - 14 (from LMP)</p>
            <p>Fertile Window Start = Ovulation Day - 5</p>
            <p>Fertile Window End = Ovulation Day + 1</p>
            <p>Next Period = LMP + Cycle Length</p>
            <p className="text-xs text-muted-foreground mt-2">Egg survives 12-24 hrs after ovulation - Sperm survive 3-5 days</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What is Your Fertile Window and When is It</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Cycle Length", "Ovulation Day", "Fertile Window", "Next Period"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {CYCLE_REFERENCE.map(([cycle, ovDay, window, period]) => (
                  <tr key={cycle} className={`hover:bg-muted/30 ${cycle === `${cycleLength}-day cycle` ? "bg-teal-50 dark:bg-teal-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-teal-600 dark:text-teal-400">{cycle}</td>
                    <td className="py-2.5 px-4 text-foreground">{ovDay}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{window}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{period}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Conception and Ovulation Calculator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to review your result quickly, compare reference ranges, and make a more informed health or fitness estimate without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/pregnancy-conception-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


